    EmailIcon,
    FacebookIcon,
    InstapaperIcon,
    LineIcon,
    LinkedinIcon,
    LivejournalIcon,
    MailruIcon,
    OKIcon,
    PinterestIcon,
    PocketIcon,
    RedditIcon,
    TelegramIcon,
    TumblrIcon,
    TwitterIcon,
    ViberIcon,
    VKIcon,
    WeiboIcon,
    WhatsappIcon,
    WorkplaceIcon,
  } from "react-share";

class App extends Component {

    constructor(props) {
        super(props)
        this.state = {
            items : [],
            currentItem : {
                text : '' ,
                key : ''
        }
    }
}

    render() {

        const style = {
            margintop: '100px',
            marginleft: '300px'
        }



